233	async function orchestrateSession(options = {}) {
234	  const { sessionState, executorConfig } = normalizeOptions(options);
235	  const packetSpecFolder = resolvePacketSpecFolder(sessionState, executorConfig);
236	  const statePath = sessionStatePath(packetSpecFolder);
237	  const guards = normalizeGuards(sessionState, executorConfig);
238	  const runTopic = executorConfig.orchestrateTopic || executorConfig.orchestrate_topic || orchestrateTopic;
239	  if (typeof runTopic !== 'function') {
240	    throw new TypeError('executor_config.orchestrateTopic must be a function when provided');
241	  }
242	
243	  const topicResults = [];
244	  const skippedTopicIds = [];
245	  let stopReason = 'topics_exhausted';
246	
247	  for (let index = 0; index < sessionState.topics.length; index += 1) {
248	    const topicNumber = index + 1;
249	    const topic = sessionState.topics[index];
250	    const maxTopicDecision = evaluateCouncilCostGuards({
251	      topicNumber,
252	      guards,
253	    });
254	    if (topicNumber > guards.max_topics_per_session || maxTopicDecision.stop_reasons.includes('max_topics_per_session')) {
255	      stopReason = 'max_topics_per_session';
256	      skippedTopicIds.push(...sessionState.topics.slice(index).map((entry) => entry.topic_id));
257	      break;
258	    }
259	
260	    const priors = index === 0 ? [] : getCrossTopicPriors(packetSpecFolder, { topic_id: topic.topic_id });
261	    const enriched = withCrossTopicPriors(topic, {
262	      ...sessionState,
263	      session: {
264	        ...sessionState.session,
265	        current_topic: topicNumber,
266	      },
267	    }, executorConfig, priors);
268	
269	    const topicResult = await runTopic({
270	      topic_id: enriched.topic.topic_id,
271	      session_state: {
272	        ...enriched.sessionState,
273	        session: {
274	          ...enriched.sessionState.session,
275	          current_topic: topicNumber,
276	        },
277	        current: {
278	          ...enriched.sessionState.current,
279	          topic: enriched.topic,
280	        },
281	      },
282	      executor_config: enriched.executorConfig,
283	    });
284	    topicResults.push(topicResult);
285	    appendFinding(packetSpecFolder, topicFinding(enriched.topic, topicResult, sessionState));
286	
287	    appendTopicCompletion(statePath, {
288	      session_id: sessionState.session.session_id,
289	      topic_id: enriched.topic.topic_id,
290	      topic_number: topicNumber,
291	      rounds_completed: topicResult.rounds_completed,
292	      final_verdict: topicResult.final_verdict,
293	      stability_score: topicResult.stability_score,
