297	    const saturationDecision = sessionSaturationDecision(topicResult, topicResults.length, guards, executorConfig);
298	    if (saturationDecision.stop_reasons.includes('saturation_threshold')) {
299	      stopReason = 'session_saturation_threshold';
300	      skippedTopicIds.push(...sessionState.topics.slice(index + 1).map((entry) => entry.topic_id));
301	      break;
302	    }
303	
304	    if (topicResults.length >= guards.max_topics_per_session && topicNumber < sessionState.topics.length) {
305	      stopReason = 'max_topics_per_session';
306	      skippedTopicIds.push(...sessionState.topics.slice(index + 1).map((entry) => entry.topic_id));
307	      break;
308	    }
