// 5. EXPORTS
// ─────────────────────────────────────────────────────────────────────────────

module.exports = {
  DEFAULT_COUNCIL_COST_GUARDS,
  computeCouncilCostUpperBound,
  evaluateCouncilCostGuards,
  evaluateLagCeilingTripwire,
  normalizeCostGuards,
};
